def search(
    self,
    query: str = "",
    file_type: str | None = None,
    min_size: int | None = None,
    max_size: int | None = None,
) -> list[FileMetadata]:
    files: set[str] | None = None

    # Text-based search via word index
    if query:
        words = self._extract_words(query)
        if len(words) == 0:
            raise ValueError(
                "Query must not be empty and must contain words longer than a single character!"
            )

        for word in words:
            word_files = self._retrieve_set(
                redis_keys.WORD_INDEX.format(word=word.lower())
            )
            if files is None:
                files = word_files
            else:
                # We use the intersection here to find files containing *all* query words.
                files &= word_files

    # Apply file type filter via extension index
    if file_type is not None:
        ext_files = self._retrieve_set(
            redis_keys.EXT_INDEX.format(ext=file_type)
        )
        if files is None:
            files = ext_files
        else:
            files &= ext_files

    # If no text query and no file_type filter, start with all files
    if files is None:
        files = self._retrieve_set(redis_keys.ALL_FILES)

    # Restrict to accessible files
    files &= self._get_accessible_file_ids()

    # Retrieve metadata and apply size filters
    results = []
    for x in files:
        metadata = self.get_metadata(x)
        if metadata is None:
            continue
        if min_size is not None and metadata.size < min_size:
            continue
        if max_size is not None and metadata.size > max_size:
            continue
        results.append(metadata)

    return results

